#include <bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5;

int st[N][25];

int query(int l, int r)
{
    int len = r - l + 1;
    int b = __lg(len);
    return min(st[l][b], st[r - (1 << b) + 1][b]);
}

int main()
{
    int n, m;
    cin >> n >> m;
    ios::sync_with_stdio(false);
    cin.tie(0);
    for(int i = 1; i <= n; i++)
        cin >> st[i][0];
    int lgn = __lg(n);
    for(int i = 1; i <= lgn; i++)
    {
        int len = 1 << i, len2 = len / 2;
        for(int j = 1; j + len <= n + 1; j++)
            st[j][i] = min(st[j][i - 1], st[j + len2][i - 1]);
    }
    for(int i = 1; i <= m; i++)
    {
        int l, r;
        cin >> l >> r;
        cout << query(l, r) << ' ';
    }
    return 0;
}
